namespace sv_e308108c78d440f5a2f649663eb9141f.Models;

public class Product
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
    public string Category { get; set; } = "";
}

using sv_e308108c78d440f5a2f649663eb9141f.Models;

namespace sv_e308108c78d440f5a2f649663eb9141f.Services;

public class InventoryService
{
    private readonly List<Product> _products =
    [
        new() { Id = 1, Name = "Laptop", Quantity = 25, UnitPrice = 999.99m, Category = "Electronics" },
        new() { Id = 2, Name = "T-Shirt", Quantity = 150, UnitPrice = 19.99m, Category = "Clothing" },
        new() { Id = 3, Name = "Organic Coffee", Quantity = 80, UnitPrice = 12.50m, Category = "Food" },
        new() { Id = 4, Name = "Wireless Mouse", Quantity = 60, UnitPrice = 29.99m, Category = "Electronics" },
        new() { Id = 5, Name = "Winter Jacket", Quantity = 35, UnitPrice = 89.95m, Category = "Clothing" },
        new() { Id = 6, Name = "Notebook Set", Quantity = 200, UnitPrice = 7.49m, Category = "Other" },
    ];

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var snapshot = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category,
            }).ToList();

            return Task.FromResult(snapshot);
        }
    }

    public Task UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == updated.Id)
                ?? throw new InvalidOperationException($"Product with Id {updated.Id} not found.");

            existing.Name = updated.Name;
            existing.Quantity = updated.Quantity;
            existing.UnitPrice = updated.UnitPrice;
            existing.Category = updated.Category;
        }

        return Task.CompletedTask;
    }
}

